import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { productActions, productStrings } from "../../../config";
import { SimpleListBoard } from '../../../../../includes';
import { Grid } from '@material-ui/core';
import { colors } from '../../../../../../utils';
const style = theme => ({
    root: {
    },
    header : {
        color : colors.secondary,
        fontWeight : "bold"
    }
})
class _ItemOverview extends Component {
    constructor(props) {
        super(props);
    }
    componentWillUnmount(){
        const {dispatch} = this.props;
        // productActions.setItem(null)(dispatch);
    }
    render() {
        const {classes, item} = this.props;
        const {name, brand, category, purchases} = item || {};
        return (
            <Grid container spacing={2} className={classes.root}>
                <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                    <SimpleListBoard
                        cardHeaderProps={{
                            className : classes.header
                        }}
                        title="Item Information"
                        data={{name, brand, category}}
                        nameMapper={name=>name}
                        skip={[]}
                        />                    
                </Grid>
                <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                    <SimpleListBoard
                        cardHeaderProps={{
                            className : classes.header
                        }}
                        title="Purchase Information"
                        data={purchases}
                        nameMapper={name=>name}
                        skip={[]}
                        />                    
                </Grid>
                <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                    <SimpleListBoard
                        cardHeaderProps={{
                            className : classes.header
                        }}
                        title="Stock Information"
                        data={purchases}
                        nameMapper={name=>name}
                        skip={[]}
                        />                    
                </Grid>
            </Grid>
        );
    }
}


_ItemOverview.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({productReducer}) => ({
    [productStrings.item] : productReducer[productStrings.item],
})


export const ItemOverview = connect(mapStateToProps)(withStyles(style)(_ItemOverview));
export {ItemOverview as default}