import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, MyCustomTabs } from '../../../../includes';
import { routeNamesInventory } from '../../../routeNames';
import ItemOverview from './ItemOverview/ItemOverview';
import { Iteminfo } from './ItemInfo';
import { ItemPurchaseOrders } from './ItemPurchaseOrders';
import { ItemSaleOder } from './ItemSaleOder';
import { ItemIncoming } from './ItemIncoming';
import { productActions } from '../../actions';


const style = theme => ({
    root: {
    }
})
class _Item extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tabValue : null
        }
        this.ItemId = props.match.params.id;
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "ITEM",
            [headerStrings.backButtonAction] : ()=>{},
        })(dispatch);
        breadCrumbActions.addToBreadCrumb([
            {name : "Item", path : routeNamesInventory.item_+this.ItemId}
        ])(dispatch);
        mainStageHeaderAction({})(dispatch);
        
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {dispatch} = this.props;
        productActions.getItem(this.itemId)(dispatch);
    }
    setInitialTabValue = tabValue => {
        this.setState({tabValue});
    }
    render() {
        const {classes} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    position="sticky"
                    tabs={{
                        overview : "Overview",
                        info : "Info",
                        pOrder : "Purchase Orders",
                        sOrder : "Sale Orders",                        
                        incoming : "Incoming",                        
                    }}
                    getInitialTabValue={this.setInitialTabValue.bind(this)}
                    />
                    <div style={{marginTop : 20}}>
                        {tabValue === "overview" && <ItemOverview/>}
                        {tabValue === "info" && <Iteminfo/>}
                        {tabValue === "pOrder" && <ItemPurchaseOrders/>}
                        {tabValue === "sOrder" && <ItemSaleOder/>}
                        {tabValue === "incoming" && <ItemIncoming/>}
                    </div>
            </div>
        );
    }
}


_Item.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const Item = connect(mapStateToProps)(withStyles(style)(_Item));
export {Item as default}